package com.panini.back.controller; import com.panini.back.dto.AuthDtos.*; import com.panini.back.service.AuthService; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/api/auth") @CrossOrigin(origins = "*") public class AuthController { private final AuthService auth; public AuthController(AuthService auth){ this.auth=auth; } @PostMapping("/register") public AuthResponse register(@RequestBody RegisterRequest r){ return auth.register(r); } @PostMapping("/login") public AuthResponse login(@RequestBody LoginRequest r){ return auth.login(r); } }
